import React, { Component } from 'react'
import logo from '../../assets/images/logo1.png'
import { Link } from "react-router-dom";
import Axios from '../../Config/Axios';
import { authHeaders, toasterAlert as toastAlert, setSession, isAuthenticated, getToken } from "../../Helpers/Functions";
import Redirect from "../../Utils/history";
import GoogleLogin from 'react-google-login';
import userAuthenicated from '../../Services/auth.service'
import Gpic from "../../assets/images/gPic.png";
class ForgetPassword extends Component {
    state = {
        email: '', loading: false, errors: {
            email: ''
        }
    };

    componentDidMount() {
        if (isAuthenticated()) {
            window.location.href = `/`;
        }
    }
    onChangeState = (event) => {
        const { name, value } = event.target;
        this.setState({ [name]: value })
        console.log('name', this.state.email);

    }
    responseGoogle = (response) => {
        console.log(response);
        // Google Access Token
        if(response.accessToken !== undefined){
            Axios.get('/callback?authToken=' + response.accessToken).then(response => {
                // console.log('Google signin --- '+ JSON.stringify(response));
                // Authenticated Service
                userAuthenicated.userAuthResponseHandler(response);
            }).catch(error => {
                console.log(error, 'error data')
                // if(!error.response.data.errors?.outcome_id )
    
                toastAlert('error', 'Authentication Failed!')
                //
                // return error.response
            }).finally(() => {
                this.setState({ loading: false });
            });
        }
    }
    login = () => {
        const { email } = this.state;
        let { emailError } = '';

        if (!email) {
            emailError = "Email is required";
        }

        this.setState({
            errors: {
                email: emailError,
            }
        })
        if (emailError) {
            return true;
        }
        this.setState({ loading: true });
        Axios.post(`/forgetPassword`, { email }).then(response => {
            console.log(response);
            if(response.status === 200){
                localStorage.setItem('forgetEmail', email);
                console.log('response.data.accessToken ' + response.data.accessToken)
                localStorage.setItem('resetAccessToken', response.data.accessToken);
                console.log(response.data);
                Redirect.push('/VerifyToken');
            }
            // Authenticated Service
            // userAuthenicated.userAuthResponseHandler(response);
            // console.log('getToken......' + response);
        }).catch(error => {
            console.log(error, 'error data')
            // if(!error.response.data.errors?.outcome_id )

            toastAlert('error', 'Authentication Failed!')
            //
            // return error.response
        }).finally(() => {
            this.setState({ loading: false });
        });

        // Axios.post('https://reqres.in/api/articles', {email,password} )
        //     .then(response => console.log(response));
    }
    render() {

        return (
            <>
                <div className="container-fluid login-wrapper">
                    <div className="row mar-width-0 width-wrap">
                        <div className="col-md-12 text-center pt-2">
                            <Link to="/"> <img src={logo} alt="" /></Link>
                        </div>
                        <div className="col-md-12 login-heading">
                            <p className="font-family">Make the most of your professional life</p>
                        </div>

                        <div className="row mar-width-0 form-bg">
                            <div className="col-md-12 p-0">
                                <h3 className="font-family lo-title">Forget Password</h3>
                            </div>
                            <div className="col-md-12 form-wrap p-0">
                                <form className="w-100">
                                    <div className="form-group">
                                        <label htmlFor="exampleInputEmail1">Please Enter Your Email</label>
                                        <input type="email" name="email" onChange={this.onChangeState} value={this.state.email} className="form-control" id="exampleInputEmail1"
                                        />
                                        <span className="error">{this.state.errors.email}</span>
                                    </div>
                                    <button type="button" disabled={this.state.loading} onClick={this.login} className="btn btn-primary btnLogin">Send Code</button>
                                </form>
                            </div>
                            {/* <div className="col-md-12 or-wrap">
                                <h2 className="h2_2"><span>or</span></h2>
                            </div>
                            <div className="col-md-12">
                                <GoogleLogin
                                    clientId="340365300393-1ma31t11b7akqn61tsbpt8h0g9e134a7.apps.googleusercontent.com"
                                    render={renderProps => (
                                        <button onClick={renderProps.onClick} disabled={renderProps.disabled} className="btn btn-primary btnGoogle"><img className="gpic" src={Gpic} alt="" /> Login with Google</button>
                                    )}
                                    buttonText="Login"
                                    buttonText="Login"
                                    onSuccess={this.responseGoogle}
                                    onFailure={this.responseGoogle}
                                    cookiePolicy={'single_host_origin'}
                                />

                            </div> */}
                            <div className="col-md-12 bottom-wrap2">
                                <span>Don't have an account yet?</span> &nbsp;
                                <Link to="/signup" className="">Sign Up</Link>

                            </div>
                        </div>



                    </div>
                </div>
            </>
        )
    }
}

export default ForgetPassword
